import React, { useState } from 'react';
import './App.css';

const MAX_WORDS = 100;

const BUTTONS = [
  { label: 'Professional', tone: 'professional' },
  { label: 'Friend', tone: 'friend' },
  { label: 'General', tone: 'general' },
  { label: 'Professional', tone: 'professional' },
  { label: 'Friend', tone: 'friend' },
  { label: 'General', tone: 'general' },
];

function App() {
  const [text, setText] = useState('');
  const [selected, setSelected] = useState(null);
  const [result, setResult] = useState('');

  const handleChange = (e) => {
    const value = e.target.value;
    const wordCount = value.trim().split(/\s+/).filter(Boolean).length;
    if (wordCount <= MAX_WORDS || value.length < text.length) {
      setText(value);
    }
  };

  const wordCount = text.trim().split(/\s+/).filter(Boolean).length;

  // 🔧 Replace this with a real API call when you're ready —
  // this is just a placeholder so the UI has something to show.
  const generateResult = (tone) => {
    if (!text.trim()) return 'Please type a sentence first.';
    const templates = {
      professional: `Professional version: "${text.trim()}"`,
      friend: `Friendly version: "${text.trim()}"`,
      general: `General version: "${text.trim()}"`,
    };
    return templates[tone];
  };

  const handleClick = (index, tone) => {
    setSelected(index);
    setResult(generateResult(tone));
  };

  return (
    <div className="page">
      <div className="rectangle">
        <h1 className="title">Rewrite Your Message</h1>

        <textarea
          className="text-input"
          placeholder="Type your sentence here..."
          value={text}
          onChange={handleChange}
        />
        <div className={`word-count ${wordCount >= MAX_WORDS ? 'limit' : ''}`}>
          {wordCount}/{MAX_WORDS} words
        </div>

        <div className="button-grid">
          {BUTTONS.map((btn, i) => (
            <button
              key={i}
              className={`btn btn-${btn.tone} ${selected === i ? 'active' : ''}`}
              onClick={() => handleClick(i, btn.tone)}
            >
              {btn.label}
            </button>
          ))}
        </div>

        {result && (
          <div className={`result-label result-${BUTTONS[selected].tone}`}>
            {result}
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
